/* stackless_example.c - Example of stackless coroutine usage
 *
 * This demonstrates how users write code using the stackless API.
 * The producer/consumer pattern is implemented without any assembly
 * or stack switching—just pure C with macros.
 */
#include "kcoro_stackless.h"
#include <stdio.h>

/* User-defined state struct for producer.
 * All local variables that must persist across suspension go here. */
struct producer_state {
    int ticket;
    int i;
    int data;
};

/* Producer coroutine: sends 5 messages.
 * This function is called repeatedly by the scheduler until it completes. */
void* producer_step(koro_cont_t* k)
{
    /* Cast user_data to our state struct */
    struct producer_state* s = (struct producer_state*)k->user_data;
    
    /* Extract ticket from user_arg (passed at creation) */
    if (k->state == 0) {
        s->ticket = (int)(intptr_t)k->user_arg;
    }
    
    /* State machine generated by macros */
    KORO_BEGIN(k);
    
    printf("Producer: Starting on ticket %d\n", s->ticket);
    
    for (s->i = 0; s->i < 5; s->i++) {
        s->data = s->i * 100;
        printf("Producer: Sending %d\n", s->data);
        
        /* This suspends if arena is full.
         * Macro expands to save state and return NULL. */
        KORO_SEND(k, s->ticket, &s->data, sizeof(s->data));
        
        /* Execution resumes here after arena accepts the message */
        printf("Producer: Sent %d successfully\n", s->data);
    }
    
    printf("Producer: Finished\n");
    
    KORO_END(k);
}

/* User-defined state struct for consumer */
struct consumer_state {
    int ticket;
    int count;
    int* received_data;
};

/* Consumer coroutine: receives 5 messages */
void* consumer_step(koro_cont_t* k)
{
    struct consumer_state* s = (struct consumer_state*)k->user_data;
    
    if (k->state == 0) {
        s->ticket = (int)(intptr_t)k->user_arg;
        s->count = 0;
    }
    
    KORO_BEGIN(k);
    
    printf("Consumer: Starting on ticket %d\n", s->ticket);
    
    while (s->count < 5) {
        printf("Consumer: Waiting for message %d\n", s->count);
        
        /* This suspends if arena is empty.
         * After resume, data is in k->arena_payload. */
        KORO_RECV(k, s->ticket);
        
        /* Extract received data */
        s->received_data = (int*)k->arena_payload;
        printf("Consumer: Received %d\n", *s->received_data);
        s->count++;
    }
    
    printf("Consumer: Finished\n");
    
    KORO_END(k);
}

/* Minimal scheduler simulation for demonstration */
int main(void)
{
    printf("=== Stackless Coroutine Example ===\n\n");
    
    /* Create producer and consumer coroutines */
    koro_cont_t* producer = koro_cont_create(
        producer_step,
        (void*)(intptr_t)42,  /* ticket number */
        sizeof(struct producer_state)
    );
    
    koro_cont_t* consumer = koro_cont_create(
        consumer_step,
        (void*)(intptr_t)42,  /* same ticket */
        sizeof(struct consumer_state)
    );
    
    if (!producer || !consumer) {
        fprintf(stderr, "Failed to create coroutines\n");
        return 1;
    }
    
    /* Simple round-robin scheduler simulation */
    int producer_done = 0, consumer_done = 0;
    int max_iterations = 1000;
    int iteration = 0;
    
    while ((!producer_done || !consumer_done) && iteration < max_iterations) {
        iteration++;
        
        /* Step producer */
        if (!producer_done) {
            void* result = koro_cont_step(producer);
            if (result != NULL) {
                printf("\n>>> Producer completed <<<\n\n");
                producer_done = 1;
            }
        }
        
        /* Step consumer */
        if (!consumer_done) {
            void* result = koro_cont_step(consumer);
            if (result != NULL) {
                printf("\n>>> Consumer completed <<<\n\n");
                consumer_done = 1;
            }
        }
    }
    
    if (iteration >= max_iterations) {
        printf("Warning: Hit iteration limit\n");
    }
    
    /* Cleanup */
    koro_cont_destroy(producer);
    koro_cont_destroy(consumer);
    
    printf("\n=== Example Complete ===\n");
    return 0;
}
